code = """import json

articles_path = locals()['var_functions.query_db:48']

# Load all articles
with open(articles_path, 'r') as f:
    articles = json.load(f)

# Define more specific sports keywords
sports_keywords = [
    "nba", "nfl", "mlb", "nhl", "olympics", "olympic",
    "football", "basketball", "soccer", "baseball", "hockey",
    "tennis", "golf", "cricket", "rugby", "volleyball",
    "swimming", "cycling", "boxing", "wrestling", "gymnastics",
    "world cup", "championship", "tournament", "marathon",
    "medal", "medals", "champion", "champions", "playoffs"
]

# Find sports articles and track longest description
max_desc_len = 0
longest_sports_article = None
sports_count = 0

for article in articles:
    title_lower = article.get("title", "").lower()
    desc_lower = article.get("description", "").lower()
    
    # Check if it's a sports article
    is_sports = any(keyword in title_lower or keyword in desc_lower for keyword in sports_keywords)
    
    if is_sports:
        sports_count += 1
        desc = article.get("description", "")
        desc_len = len(desc)
        
        if desc_len > max_desc_len:
            max_desc_len = desc_len
            longest_sports_article = article.get("title")

print(f"Found {sports_count} sports articles")
print(f"Longest description: {max_desc_len} characters")
print(f"Title: {longest_sports_article}")

result = longest_sports_article if longest_sports_article else "No sports articles found"
print("__RESULT__:")
print(json.dumps(result))"""

